import React, { useState, useEffect, useMemo } from 'react';
import Select from 'react-select';
import './AddPurchase.css';

const AddOutflow = ({ handleAdd, locations }) => {
  const initialOutflowState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    width: null,
    lotnumber: '',
  };

  const [newOutflow, setNewOutflow] = useState(initialOutflowState);
  const [showExtras, setShowExtras] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      if (newOutflow.materialid) {
        try {
          const [responseList] = await Promise.all([
            fetch(`http://localhost:8081/materiallist/${newPurchase.materialid}`),
          ]);

          const [dataList] = await Promise.all([
            responseList.json(),
          ]);

          if (dataList && dataList.extras === 1) {
            setShowExtras(true);
          } else {
            setShowExtras(false);
          }

          setNewOutflow((prevOutflow) => ({
            ...prevOutflow,
            materialname: dataList && dataList.name ? dataList.name : '',
          }));
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      } else {
        setShowExtras(false);
        setNewOutflow((prevPurchase) => ({
          ...prevPurchase,
          materialname: '',
        }));
      }
    };

    fetchData();
  }, [newOutflow.materialid]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewOutflow((prevOutflow) => ({
      ...prevOutflow,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {

      handleAdd(newPurchase);

      setNewOutflow(initialOutflowState);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="add-purchase-form">
      <div>
        <label>Location:</label>
        <select name="location" value={newOutflow.location} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={newOutflow.materialid} onChange={handleChange} required />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={newOutflow.materialname} readOnly required />
      </div>
      {showExtras && (
        <div>
          <label>Width:</label>
          <input
            type="number"
            name="width"
            value={newOutflow.width || ''}
            onChange={handleChange}
            required
          />
        </div>
      )}
      {showExtras && (
        <div>
          <label>LOT#:</label>
          <input
            type="text"
            name="lotnumber"
            value={newOutflow.lotnumber || ''}
            onChange={handleChange}
            required
          />
        </div>
      )}
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={newOutflow.quantity} onChange={handleChange} required />
      </div>
      <button type="submit" className="add_purchase_btn">
        Add Purchase
      </button>
    </form>
  );
};

export default AddPurchase;
